import logo from "./logo.svg";
import "./App.css";
import Typewriter from "typewriter-effect";
import React, { useState } from "react";

function App() {
  return (
    <div className="App">
      <header className="App-header">
        <h1 className="left-header">
          <Typewriter
            options={{
              loop: true,
              typingSpeed: 50, // Typing speed for each character
              delay: 50, // Pause between strings
            }}
            onInit={(typewriter) => {
              typewriter
                .typeString(
                  `HELLO, I'M <span class="highlight">BURGEON</span>,<br/> A WEB DEVELOPER 😍 `
                )
                .pauseFor(1000)
                .deleteAll()
                .typeString(
                  `I'M PASSIONATE ABOUT CREATING,<span class="highlight"><br/> INTERESTING</span><br/> WEB PAGES 👌`
                )
                .pauseFor(1000)
                .deleteAll()
                .typeString(
                  `LET'S BUILD SOMETHING AMAZING <span class="highlight"><br/>TOGETHER</span> 💪`
                )
                .pauseFor(500)
                .deleteAll()
                .start();
            }}
          />
        </h1>

        <Navbar />
      </header>
    </div>
  );
}

export default App;

const Profile = () => {
  return (
    <>
      <div>
        <img src="#" alt="burgeon" className="display-pic" />
        <h1>
          Hello <span>I'm Burgeon</span>
        </h1>
      </div>
    </>
  );
};

const Navbar = ({ activeSection, onNavClick }) => {
  return (
    <nav className="navbar">
      <ul>
        <li
          className={activeSection === "about" ? "active" : ""}
          onClick={() => onNavClick("about")}
        >
          About
        </li>
        <li
          className={activeSection === "skills" ? "active" : ""}
          onClick={() => onNavClick("skills")}
        >
          Skills
        </li>
        <li
          className={activeSection === "contact" ? "active" : ""}
          onClick={() => onNavClick("contact")}
        >
          Contact Me
        </li>
      </ul>
    </nav>
  );
};
const Skills = () => {};
const Contact = () => {};
